    42→async function runReviewer(
    43→  ctx: AppContext,
    44→  skillName: string
    45→): Promise<Record<string, unknown>> {
    46→  return withSpan(ctx.tracer, "runReviewer", async () => {
    47→    const env = Object.fromEntries(
    48→      Object.entries(process.env).filter(([k]) => k !== "CLAUDECODE")
    49→    );
    50→
    51→    const cmd = ["claude", "-p", `/${skillName} ci`, "--output-format", "json"];
    52→    ctx.logger.info("Running reviewer command", { command: cmd.join(" ") });
    53→    console.error(`Running command: ${cmd.join(" ")}`);
    54→
    55→    const proc = Bun.spawn(cmd, {
    56→      stdout: "pipe",
    57→      stderr: "pipe",
    58→      env,
    59→    });
    60→
    61→    const stdout = await new Response(proc.stdout).text();
    62→    const stderr = await new Response(proc.stderr).text();
    63→    const exitCode = await proc.exited;
    64→
    65→    ctx.logger.debug("Reviewer process completed", {
    66→      exitCode,
    67→      stdoutLength: stdout.length,
    68→      stderrLength: stderr.length,
    69→    });
    70→    console.error(`Return code: ${exitCode}`);
    71→    console.error(`Stdout length: ${stdout.length}`);
    72→    console.error(`Stderr: ${stderr.slice(0, 500) || "(empty)"}`);
    73→
    74→    if (exitCode !== 0) {
    75→      ctx.logger.error("Reviewer failed", { exitCode, stderr });
    76→      console.error(`Error running reviewer: ${stderr}`);
    77→      process.exit(1);
    78→    }
    79→
    80→    // Parse the outer JSON from claude CLI
    81→    let claudeOutput: Record<string, unknown>;
    82→    try {
    83→      claudeOutput = JSON.parse(stdout);
    84→    } catch (e) {
    85→      ctx.logger.error("Failed to parse claude output", { error: e });
    86→      console.error(`Failed to parse claude output as JSON: ${e}`);
    87→      console.error(`Raw output: ${stdout.slice(0, 500)}`);
    88→      process.exit(1);
    89→    }
    90→
    91→    // Extract the result field
    92→    if (!("result" in claudeOutput)) {
    93→      ctx.logger.error("No result field in claude output");
    94→      console.error("No 'result' field in claude output");
    95→      process.exit(1);
    96→    }
    97→
    98→    const reviewerOutput = claudeOutput.result;
    99→
   100→    if (typeof reviewerOutput === "object" && reviewerOutput !== null) {
   101→      return reviewerOutput as Record<string, unknown>;
   102→    }
   103→
   104→    // Try to parse as JSON string
   105→    if (typeof reviewerOutput === "string") {
   106→      try {
   107→        return JSON.parse(reviewerOutput);
   108→      } catch {
   109→        // Try to extract JSON from the response
   110→        const match = /\{[\s\S]*\}/.exec(reviewerOutput);
   111→        if (match) {
   112→          return JSON.parse(match[0]);
   113→        }
   114→      }
   115→    }
   116→
   117→    ctx.logger.error("Could not extract JSON from reviewer output");
   118→    console.error("Could not extract JSON from reviewer output");
   119→    console.error(`Output: ${String(reviewerOutput).slice(0, 500)}`);
   120→    process.exit(1);
   121→  }, { skill: skillName });
   122→}
