   124→function parseReviewResult(
   125→  skillName: string,
   126→  data: Record<string, unknown>
   127→): ReviewResult {
   128→  const findings: Finding[] = [];
   129→  const rawFindings = data.findings;
   130→
   131→  if (Array.isArray(rawFindings)) {
   132→    for (const f of rawFindings) {
   133→      if (typeof f !== "object" || f === null) continue;
   134→      const finding = f as Record<string, unknown>;
   135→
   136→      let location: Location | null = null;
   137→      if (finding.location && typeof finding.location === "object") {
   138→        const loc = finding.location as Record<string, unknown>;
   139→        if (typeof loc.file === "string" && typeof loc.line === "number") {
   140→          location = {
   141→            file: loc.file,
   142→            line: loc.line,
   143→            endLine: typeof loc.endLine === "number" ? loc.endLine : undefined,
   144→          };
   145→        }
   146→      }
   147→
   148→      findings.push({
   149→        requirement: String(finding.requirement || ""),
   150→        status: String(finding.status || "info"),
   151→        severity: String(finding.severity || "info"),
   152→        details: String(finding.details || ""),
   153→        location,
   154→      });
   155→    }
   156→  }
   157→
   158→  return {
   159→    reviewerName: skillName,
   160→    status: String(data.status || "warn"),
   161→    summary: String(data.summary || ""),
   162→    findings,
   163→  };
   164→}
