   166→export async function handler(ctx: AppContext, options: ReviewOptions): Promise<void> {
   167→  return withSpan(ctx.tracer, "review", async () => {
   168→    ctx.logger.info("Starting review command", { skill: options.skill, pr: options.pr });
   169→
   170→    const prNumber = options.pr ?? (await getCurrentPR());
   171→    if (!prNumber) {
   172→      ctx.logger.error("Could not detect PR number");
   173→      console.error("Could not detect PR number. Use --pr to specify.");
   174→      process.exit(1);
   175→    }
   176→
   177→    const baseBranch = options.base ?? "main";
   178→    const dryRun = options.dryRun ?? false;
   179→
   180→    ctx.logger.info("Review configuration", { prNumber, baseBranch, dryRun });
   181→    console.log(`Running reviewer '${options.skill}' for PR #${prNumber}...`);
   182→
   183→    // Get diff lines for validation
   184→    const diffLines = await withSpan(ctx.tracer, "getDiffLines", () => getDiffLines(baseBranch));
   185→
   186→    // Run the reviewer
   187→    const rawResult = await runReviewer(ctx, options.skill);
   188→    const result = parseReviewResult(options.skill, rawResult);
   189→
   190→    ctx.logger.info("Review complete", {
   191→      status: result.status,
   192→      findingsCount: result.findings.length,
   193→    });
   194→    console.log(`Review complete: ${result.status.toUpperCase()} - ${result.summary}`);
   195→    console.log(`Found ${result.findings.length} finding(s)`);
   196→
   197→    // Separate findings with and without locations
   198→    const diffFindings: Finding[] = [];
   199→    const generalFindings: Finding[] = [];
   200→
   201→    for (const finding of result.findings) {
   202→      if (finding.location) {
   203→        const fileLines = diffLines.get(finding.location.file);
   204→        if (fileLines?.has(finding.location.line)) {
   205→          diffFindings.push(finding);
   206→        } else {
   207→          ctx.logger.debug("Finding not in diff", {
   208→            file: finding.location.file,
   209→            line: finding.location.line,
   210→          });
   211→          console.log(
   212→            `  Note: ${finding.location.file}:${finding.location.line} not in diff, adding to general findings`
   213→          );
   214→          generalFindings.push(finding);
   215→        }
   216→      } else {
   217→        generalFindings.push(finding);
   218→      }
   219→    }
   220→
   221→    ctx.logger.info("Categorized findings", {
   222→      diffFindings: diffFindings.length,
   223→      generalFindings: generalFindings.length,
   224→    });
   225→
   226→    // Submit the review with all diff comments and general findings
   227→    const reviewResult = await withSpan(
   228→      ctx.tracer,
   229→      "submitReview",
   230→      () => submitReview(prNumber, result, diffFindings, generalFindings, dryRun, ctx.logger),
   231→      { prNumber, dryRun }
   232→    );
   233→
   234→    if (!reviewResult.success) {
   235→      ctx.logger.error("Failed to submit review");
   236→      console.error("Failed to submit review");
   237→      process.exit(1);
   238→    }
   239→
   240→    if (reviewResult.failedFindings.length > 0) {
   241→      ctx.logger.warn("Some findings could not be posted", {
   242→        count: reviewResult.failedFindings.length,
   243→      });
   244→      console.log(`  ${reviewResult.failedFindings.length} finding(s) could not be posted as diff comments`);
   245→    }
   246→
   247→    // Print PR link
   248→    const prUrl = await getPRUrl(prNumber);
   249→    if (prUrl) {
   250→      console.log(`\nPR: ${prUrl}`);
   251→    } else {
   252→      console.log(`\nDone! (PR #${prNumber})`);
   253→    }
   254→
   255→    ctx.logger.info("Review submitted successfully", { prNumber, prUrl });
   256→  }, { skill: options.skill });
   257→}
   258→
   259→export function builder(yargs: unknown): unknown {
   260→  return (yargs as { positional: Function; option: Function })
   261→    .positional("skill", {
   262→      describe: "Name of the reviewer skill to run (e.g., vibereq:code-review)",
   263→      type: "string",
   264→      demandOption: true,
   265→    })
   266→    .option("pr", {
   267→      describe: "PR number (auto-detected if not specified)",
   268→      type: "number",
   269→    })
   270→    .option("dry-run", {
   271→      describe: "Print what would be posted without actually posting",
   272→      type: "boolean",
   273→      default: false,
   274→    })
   275→    .option("base", {
   276→      describe: "Base branch for diff comparison",
   277→      type: "string",
   278→      default: "main",
   279→    });
   280→}
