   129→async function getCommitSha(prNumber: number, logger?: Logger): Promise<string | null> {
   130→  const tracer = getTracer();
   131→  return withSpan(tracer, "getCommitSha", async () => {
   132→    const shaResult = await runCommand([
   133→      "gh",
   134→      "pr",
   135→      "view",
   136→      String(prNumber),
   137→      "--json",
   138→      "headRefOid",
   139→      "-q",
   140→      ".headRefOid",
   141→    ]);
   142→    if (shaResult.exitCode !== 0) {
   143→      logger?.error("Failed to get PR head commit", { prNumber, stderr: shaResult.stderr });
   144→      return null;
   145→    }
   146→    return shaResult.stdout.trim();
   147→  }, { prNumber });
   148→}
   149→
   150→function buildReviewComment(finding: Finding): ReviewComment | null {
   151→  if (!finding.location) return null;
   152→
   153→  const body = formatFindingForDiffComment(finding);
   154→  const comment: ReviewComment = {
   155→    path: finding.location.file,
   156→    line: finding.location.endLine ?? finding.location.line,
   157→    body,
   158→  };
   159→
   160→  if (
   161→    finding.location.endLine &&
   162→    finding.location.endLine !== finding.location.line
   163→  ) {
   164→    comment.start_line = finding.location.line;
   165→  }
   166→
   167→  return comment;
   168→}
