   170→async function resolveReviewThread(threadId: string): Promise<boolean> {
   171→  const query = `
   172→    mutation ResolveThread($threadId: ID!) {
   173→      resolveReviewThread(input: {threadId: $threadId}) {
   174→        thread {
   175→          id
   176→        }
   177→      }
   178→    }
   179→  `;
   180→
   181→  const result = await runCommand([
   182→    "gh",
   183→    "api",
   184→    "graphql",
   185→    "-f",
   186→    `query=${query}`,
   187→    "-f",
   188→    `threadId=${threadId}`,
   189→  ]);
   190→
   191→  return result.exitCode === 0;
   192→}
   193→
   194→async function getReviewThreads(
   195→  prNumber: number
   196→): Promise<Array<{ id: string; path: string; line: number }>> {
   197→  const query = `
   198→    query GetReviewThreads($owner: String!, $repo: String!, $pr: Int!) {
   199→      repository(owner: $owner, name: $repo) {
   200→        pullRequest(number: $pr) {
   201→          reviewThreads(last: 100) {
   202→            nodes {
   203→              id
   204→              isResolved
   205→              path
   206→              line
   207→            }
   208→          }
   209→        }
   210→      }
   211→    }
   212→  `;
   213→
   214→  // Get owner and repo from gh
   215→  const repoResult = await runCommand([
   216→    "gh",
   217→    "repo",
   218→    "view",
   219→    "--json",
   220→    "owner,name",
   221→  ]);
   222→  if (repoResult.exitCode !== 0) return [];
   223→
   224→  const repoInfo = JSON.parse(repoResult.stdout);
   225→  const owner = repoInfo.owner.login;
   226→  const repo = repoInfo.name;
   227→
   228→  const result = await runCommand([
   229→    "gh",
   230→    "api",
   231→    "graphql",
   232→    "-f",
   233→    `query=${query}`,
   234→    "-f",
   235→    `owner=${owner}`,
   236→    "-f",
   237→    `repo=${repo}`,
   238→    "-F",
   239→    `pr=${prNumber}`,
   240→  ]);
   241→
   242→  if (result.exitCode !== 0) return [];
   243→
   244→  try {
   245→    const data = JSON.parse(result.stdout);
   246→    const threads = data.data.repository.pullRequest.reviewThreads.nodes;
   247→    return threads
   248→      .filter((t: { isResolved: boolean }) => !t.isResolved)
   249→      .map((t: { id: string; path: string; line: number }) => ({
   250→        id: t.id,
   251→        path: t.path,
   252→        line: t.line,
   253→      }));
   254→  } catch {
   255→    return [];
   256→  }
   257→}
   258→
   259→export async function submitReview(
   260→  prNumber: number,
   261→  result: ReviewResult,
   262→  diffFindings: Finding[],
   263→  generalFindings: Finding[],
   264→  dryRun = false,
   265→  logger?: Logger
   266→): Promise<{ success: boolean; failedFindings: Finding[] }> {
   267→  const tracer = getTracer();
   268→
   269→  return withSpan(tracer, "submitReview", async () => {
   270→    const failedFindings: Finding[] = [];
   271→
   272→    // Build review comments from diff findings
   273→    const comments: ReviewComment[] = [];
   274→    const fulfilledComments: Array<{ path: string; line: number }> = [];
   275→
   276→    for (const finding of diffFindings) {
   277→      const comment = buildReviewComment(finding);
   278→      if (comment) {
   279→        comments.push(comment);
   280→        if (finding.status === "fulfilled") {
   281→          fulfilledComments.push({ path: comment.path, line: comment.line });
   282→        }
   283→      } else {
   284→        failedFindings.push(finding);
   285→      }
   286→    }
   287→
   288→    // Build review body from general findings and summary
   289→    const reviewBody = formatReviewBody(result, generalFindings);
   290→
   291→    if (dryRun) {
   292→      logger?.info("Dry run - would submit review", { commentCount: comments.length });
   293→      console.log(`[DRY RUN] Would submit review with ${comments.length} diff comment(s)`);
   294→      for (const comment of comments) {
   295→        console.log(`  - ${comment.path}:${comment.line}`);
   296→      }
   297→      console.log(`[DRY RUN] Review body preview: ${reviewBody.slice(0, 200)}...`);
   298→      if (fulfilledComments.length > 0) {
   299→        console.log(`[DRY RUN] Would resolve ${fulfilledComments.length} fulfilled comment(s)`);
   300→      }
   301→      return { success: true, failedFindings };
   302→    }
   303→
   304→    const commitSha = await getCommitSha(prNumber, logger);
   305→    if (!commitSha) {
   306→      return { success: false, failedFindings: [...diffFindings, ...generalFindings] };
   307→    }
   308→
   309→    // Build the review payload
   310→    const payload: Record<string, unknown> = {
   311→      commit_id: commitSha,
   312→      body: reviewBody,
   313→      event: "COMMENT",
   314→    };
   315→
   316→    if (comments.length > 0) {
   317→      payload.comments = comments;
   318→    }
   319→
   320→    // Write payload to temp file for gh api
   321→    const tempFile = `/tmp/vibx-review-${Date.now()}.json`;
   322→    await Bun.write(tempFile, JSON.stringify(payload));
   323→
   324→    const createResult = await withSpan(tracer, "gh.api.createReview", () => runCommand([
   325→      "gh",
   326→      "api",
   327→      "-X",
   328→      "POST",
   329→      `/repos/{owner}/{repo}/pulls/${prNumber}/reviews`,
   330→      "--input",
   331→      tempFile,
   332→    ]));
   333→
   334→    // Clean up temp file
   335→    try {
   336→      await Bun.file(tempFile).exists() && (await runCommand(["rm", tempFile]));
   337→    } catch {
   338→      // Ignore cleanup errors
   339→    }
   340→
   341→    if (createResult.exitCode !== 0) {
   342→      logger?.error("Failed to create review", { prNumber, stderr: createResult.stderr });
   343→      return { success: false, failedFindings: [...diffFindings, ...generalFindings] };
   344→    }
   345→
   346→    logger?.info("Created review", { prNumber, commentCount: comments.length });
   347→    console.log(`Created review with ${comments.length} diff comment(s)`);
   348→
   349→    // Resolve fulfilled comments
   350→    if (fulfilledComments.length > 0) {
   351→      console.log(`Resolving ${fulfilledComments.length} fulfilled comment(s)...`);
   352→      const threads = await getReviewThreads(prNumber);
   353→
   354→      for (const fulfilled of fulfilledComments) {
   355→        const thread = threads.find(
   356→          (t) => t.path === fulfilled.path && t.line === fulfilled.line
   357→        );
   358→        if (thread) {
   359→          const resolved = await resolveReviewThread(thread.id);
   360→          if (resolved) {
   361→            logger?.debug("Resolved thread", { path: fulfilled.path, line: fulfilled.line });
   362→            console.log(`  Resolved: ${fulfilled.path}:${fulfilled.line}`);
   363→          }
   364→        }
   365→      }
   366→    }
   367→
   368→    return { success: true, failedFindings };
   369→  }, { prNumber, dryRun });
   370→}
   371→
   372→function formatReviewBody(result: ReviewResult, generalFindings: Finding[]): string {
   373→  const statusEmoji =
   374→    result.status === "pass"
   375→      ? ":white_check_mark:"
   376→      : result.status === "fail"
   377→        ? ":x:"
   378→        : ":warning:";
   379→
   380→  const lines = [
   381→    `${REVIEW_COMMENT_HEADER}`,
   382→    "",
   383→    `## ${result.reviewerName}`,
   384→    `**Overall Status:** ${statusEmoji} ${result.status.toUpperCase()}`,
   385→  ];
   386→
   387→  if (result.summary) {
   388→    lines.push("", result.summary);
   389→  }
   390→
   391→  if (generalFindings.length > 0) {
   392→    lines.push("", "### General Findings", "");
   393→    for (const finding of generalFindings) {
   394→      lines.push(formatFindingForComment(finding), "");
   395→    }
   396→  }
   397→
   398→  return lines.join("\n");
   399→}
   400→
   401→export function formatFindingForComment(finding: Finding): string {
   402→  const severityEmoji = SEVERITY_EMOJI[finding.severity] || "";
   403→  const statusEmoji = STATUS_EMOJI[finding.status] || "";
   404→
   405→  return [
   406→    `### ${severityEmoji} ${finding.requirement}`,
   407→    `**Status:** ${statusEmoji} ${finding.status} | **Severity:** ${finding.severity}`,
   408→    "",
   409→    finding.details,
   410→  ].join("\n");
   411→}
