     1→import { createLogger as createWinstonLogger, format, transports, Logger } from "winston";
     2→import {
     3→  BasicTracerProvider,
     4→  SimpleSpanProcessor,
     5→  SpanExporter,
     6→  ReadableSpan,
     7→} from "@opentelemetry/sdk-trace-base";
     8→import { Resource } from "@opentelemetry/resources";
     9→import { ATTR_SERVICE_NAME, ATTR_SERVICE_VERSION } from "@opentelemetry/semantic-conventions";
    10→import { trace, Tracer, SpanStatusCode } from "@opentelemetry/api";
    11→import * as fs from "fs";
    12→import * as path from "path";
    13→
    14→const SERVICE_NAME = "vibx";
    15→const SERVICE_VERSION = "0.1.0";
    16→
    17→export interface ObservabilityConfig {
    18→  branch: string;
    19→  baseDir?: string;
    20→}
    21→
    22→interface ExportResult {
    23→  code: number;
    24→}
    25→
    26→const ExportResultCode = {
    27→  SUCCESS: 0,
    28→  FAILED: 1,
    29→};
    30→
    31→/**
    32→ * Custom file-based span exporter that writes JSONL to disk
    33→ */
    34→export class FileSpanExporter implements SpanExporter {
    35→  private filePath: string;
    36→  private writeStream: fs.WriteStream | null = null;
    37→
    38→  constructor(outputDir: string) {
    39→    const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
    40→    this.filePath = path.join(outputDir, `trace-${timestamp}.jsonl`);
    41→
    42→    // Ensure directory exists
    43→    fs.mkdirSync(outputDir, { recursive: true });
    44→  }
    45→
    46→  export(
    47→    spans: ReadableSpan[],
    48→    resultCallback: (result: ExportResult) => void
    49→  ): void {
    50→    try {
    51→      if (!this.writeStream) {
    52→        this.writeStream = fs.createWriteStream(this.filePath, { flags: "a" });
    53→      }
    54→
    55→      for (const span of spans) {
    56→        const spanData = {
    57→          traceId: span.spanContext().traceId,
    58→          spanId: span.spanContext().spanId,
    59→          parentSpanId: span.parentSpanId,
    60→          name: span.name,
    61→          kind: span.kind,
    62→          startTime: span.startTime,
    63→          endTime: span.endTime,
    64→          status: span.status,
    65→          attributes: span.attributes,
    66→          events: span.events,
    67→          links: span.links,
    68→        };
    69→        this.writeStream.write(JSON.stringify(spanData) + "\n");
    70→      }
    71→
    72→      resultCallback({ code: ExportResultCode.SUCCESS });
    73→    } catch (error) {
    74→      resultCallback({ code: ExportResultCode.FAILED });
    75→    }
    76→  }
    77→
    78→  shutdown(): Promise<void> {
    79→    return new Promise((resolve) => {
    80→      if (this.writeStream) {
    81→        this.writeStream.end(() => resolve());
    82→      } else {
    83→        resolve();
    84→      }
    85→    });
    86→  }
    87→}
    88→
    89→/**
    90→ * Get current git branch name, sanitized for filesystem use
    91→ */
    92→export async function getCurrentBranch(): Promise<string> {
    93→  const proc = Bun.spawn(["git", "rev-parse", "--abbrev-ref", "HEAD"], {
    94→    stdout: "pipe",
    95→    stderr: "pipe",
    96→  });
    97→
    98→  const stdout = await new Response(proc.stdout).text();
    99→  const exitCode = await proc.exited;
   100→
   101→  if (exitCode !== 0) {
   102→    return "unknown";
   103→  }
   104→
   105→  return sanitizeBranchName(stdout.trim());
   106→}
   107→
   108→/**
   109→ * Sanitize branch name for filesystem safety
   110→ */
   111→export function sanitizeBranchName(branch: string): string {
   112→  return branch.replace(/[/\\:*?"<>|]/g, "-");
   113→}
   114→
   115→/**
   116→ * Get output directory for logs/traces
   117→ */
   118→function getOutputDir(branch: string, subdir: string, baseDir = "/tmp/vibx"): string {
   119→  return path.join(baseDir, branch, subdir);
   120→}
   121→
   122→/**
   123→ * Create a Winston logger configured for JSONL output
   124→ */
   125→export function createLogger(config: ObservabilityConfig): Logger {
   126→  const logDir = getOutputDir(config.branch, "logs", config.baseDir);
   127→  fs.mkdirSync(logDir, { recursive: true });
   128→
   129→  const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
   130→  const logFile = path.join(logDir, `vibx-${timestamp}.jsonl`);
   131→
   132→  return createWinstonLogger({
   133→    level: process.env.LOG_LEVEL || "info",
   134→    format: format.combine(
   135→      format.timestamp(),
   136→      format.errors({ stack: true }),
   137→      format.json()
   138→    ),
   139→    defaultMeta: {
   140→      service: SERVICE_NAME,
   141→      branch: config.branch,
   142→    },
   143→    transports: [
   144→      new transports.File({
   145→        filename: logFile,
   146→        options: { flags: "a" },
   147→      }),
   148→    ],
   149→  });
   150→}
   151→
   152→let provider: BasicTracerProvider | null = null;
   153→
   154→/**
   155→ * Initialize OpenTelemetry tracing
   156→ */
   157→export function initTracing(config: ObservabilityConfig): Tracer {
   158→  const traceDir = getOutputDir(config.branch, "traces", config.baseDir);
   159→
   160→  const exporter = new FileSpanExporter(traceDir);
   161→
   162→  provider = new BasicTracerProvider({
   163→    resource: new Resource({
   164→      [ATTR_SERVICE_NAME]: SERVICE_NAME,
   165→      [ATTR_SERVICE_VERSION]: SERVICE_VERSION,
   166→      branch: config.branch,
   167→    }),
   168→  });
   169→
   170→  provider.addSpanProcessor(new SimpleSpanProcessor(exporter));
   171→  provider.register();
   172→
   173→  return trace.getTracer(SERVICE_NAME, SERVICE_VERSION);
   174→}
   175→
   176→/**
   177→ * Get the active tracer
   178→ */
   179→export function getTracer(): Tracer {
   180→  return trace.getTracer(SERVICE_NAME, SERVICE_VERSION);
   181→}
   182→
   183→/**
   184→ * Shutdown observability (flush traces)
   185→ */
   186→export async function shutdownObservability(): Promise<void> {
   187→  if (provider) {
   188→    await provider.shutdown();
   189→    provider = null;
   190→  }
   191→}
   192→
   193→/**
   194→ * Create a span and execute a function within it
   195→ */
   196→export async function withSpan<T>(
   197→  tracer: Tracer,
   198→  name: string,
   199→  fn: () => Promise<T>,
   200→  attributes?: Record<string, string | number | boolean>
   201→): Promise<T> {
   202→  return tracer.startActiveSpan(name, async (span) => {
   203→    if (attributes) {
   204→      span.setAttributes(attributes);
   205→    }
   206→
   207→    try {
   208→      const result = await fn();
   209→      span.setStatus({ code: SpanStatusCode.OK });
   210→      return result;
   211→    } catch (error) {
   212→      span.setStatus({
   213→        code: SpanStatusCode.ERROR,
   214→        message: error instanceof Error ? error.message : String(error),
   215→      });
   216→      span.recordException(error instanceof Error ? error : new Error(String(error)));
   217→      throw error;
   218→    } finally {
   219→      span.end();
   220→    }
   221→  });
   222→}
   223→
   224→// Re-export types for convenience
   225→export type { Logger } from "winston";
   226→export type { Tracer } from "@opentelemetry/api";
   227→export { SpanStatusCode } from "@opentelemetry/api";
