     2→
     3→const CHECKPOINT_RE = /^\s*Entire-Checkpoint:\s*([0-9a-fA-F]+)\s*$/m;
     4→export const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
     5→
     6→export async function runGit(args: string[]): Promise<ProcessResult> {
     7→  const proc = Bun.spawn(["git", ...args], {
     8→    stdout: "pipe",
     9→    stderr: "pipe",
    10→  });
    11→  const stdout = await new Response(proc.stdout).text();
    12→  const stderr = await new Response(proc.stderr).text();
    13→  const exitCode = await proc.exited;
    14→  return { stdout, stderr, exitCode };
    15→}
    16→
    17→export async function getCommitsNotInMain(): Promise<string[]> {
    18→  const { stdout, exitCode } = await runGit([
    19→    "rev-parse",
    20→    "--is-inside-work-tree",
    21→  ]);
    22→  if (exitCode !== 0 || stdout.trim() !== "true") {
    23→    throw new Error("Not inside a git repository.");
    24→  }
    25→
    26→  const tryLog = async (base: string): Promise<string[] | null> => {
    27→    const result = await runGit(["log", `${base}..HEAD`, "--format=%H"]);
    28→    if (result.exitCode === 0) {
    29→      return result.stdout
    30→        .split("\n")
    31→        .map((l) => l.trim())
    32→        .filter(Boolean);
    33→    }
    34→    return null;
    35→  };
    36→
    37→  let commits = await tryLog("main");
    38→  if (commits === null) commits = await tryLog("origin/main");
    39→  if (commits === null) commits = await tryLog("HEAD~0");
    40→  if (commits === null) {
    41→    throw new Error("Unable to compute commits not in main.");
    42→  }
    43→  return commits;
    44→}
    45→
    46→export async function getCheckpointHash(
    47→  commitHash: string
    48→): Promise<string | null> {
    49→  const { stdout, exitCode } = await runGit([
    50→    "log",
    51→    "-1",
    52→    "--format=%B",
    53→    commitHash,
    54→  ]);
    55→  if (exitCode !== 0) return null;
    56→  const match = CHECKPOINT_RE.exec(stdout);
    57→  return match ? match[1].toLowerCase() : null;
    58→}
    59→
    60→export function checkpointHashToFolder(hash: string): string {
    61→  const h = hash.trim().toLowerCase();
    62→  if (h.length < 3) {
    63→    return `${h}/${h}/0`;
    64→  }
    65→  return `${h.slice(0, 2)}/${h.slice(2)}/0`;
    66→}
    67→
    68→export async function fileExistsOnBranch(
    69→  branch: string,
    70→  path: string
    71→): Promise<boolean> {
    72→  const spec = `${branch}:${path}`;
    73→  const { exitCode } = await runGit(["cat-file", "-e", spec]);
    74→  return exitCode === 0;
    75→}
    76→
    77→export async function showFile(
    78→  branch: string,
    79→  path: string
    80→): Promise<string | null> {
    81→  const spec = `${branch}:${path}`;
    82→  const { stdout, exitCode } = await runGit(["show", spec]);
    83→  if (exitCode !== 0) return null;
    84→  return stdout;
    85→}
    86→
    87→export async function commitToCheckpointBranch(
    88→  folder: string,
    89→  content: string
    90→): Promise<string> {
    91→  const relPath = `${folder}/intent.md`;
    92→
    93→  // 1. Create blob from intent content
    94→  const blobProc = Bun.spawn(["git", "hash-object", "-w", "--stdin"], {
    95→    stdin: new Response(content),
    96→    stdout: "pipe",
    97→    stderr: "pipe",
    98→  });
    99→  const blobStdout = await new Response(blobProc.stdout).text();
   100→  const blobStderr = await new Response(blobProc.stderr).text();
   101→  if ((await blobProc.exited) !== 0) {
   102→    throw new Error(`Failed to create blob: ${blobStderr}`);
   103→  }
   104→  const blobHash = blobStdout.trim();
   105→
   106→  // 2. Create a temporary index file
   107→  const tmpIndex = `/tmp/vibx-git-index-${Date.now()}`;
   108→  const env = { ...process.env, GIT_INDEX_FILE: tmpIndex };
   109→
   110→  try {
   111→    // Read current tree from checkpoint branch into temp index
   112→    const readTreeProc = Bun.spawn(["git", "read-tree", CHECKPOINT_BRANCH], {
   113→      env,
   114→      stdout: "pipe",
   115→      stderr: "pipe",
   116→    });
   117→    const readTreeStderr = await new Response(readTreeProc.stderr).text();
   118→    if ((await readTreeProc.exited) !== 0) {
   119→      throw new Error(`Failed to read tree: ${readTreeStderr}`);
   120→    }
   121→
   122→    // Add new file to index
   123→    const updateIndexProc = Bun.spawn(
   124→      [
   125→        "git",
   126→        "update-index",
   127→        "--add",
   128→        "--cacheinfo",
   129→        `100644,${blobHash},${relPath}`,
   130→      ],
   131→      { env, stdout: "pipe", stderr: "pipe" }
   132→    );
   133→    const updateIndexStderr = await new Response(updateIndexProc.stderr).text();
   134→    if ((await updateIndexProc.exited) !== 0) {
   135→      throw new Error(`Failed to update index: ${updateIndexStderr}`);
   136→    }
   137→
   138→    // Write tree
   139→    const writeTreeProc = Bun.spawn(["git", "write-tree"], {
   140→      env,
   141→      stdout: "pipe",
   142→      stderr: "pipe",
   143→    });
   144→    const writeTreeStdout = await new Response(writeTreeProc.stdout).text();
   145→    const writeTreeStderr = await new Response(writeTreeProc.stderr).text();
   146→    if ((await writeTreeProc.exited) !== 0) {
   147→      throw new Error(`Failed to write tree: ${writeTreeStderr}`);
   148→    }
   149→    const newTree = writeTreeStdout.trim();
   150→
   151→    // Get parent commit
   152→    const { stdout: parentStdout, exitCode: parentExitCode } = await runGit([
   153→      "rev-parse",
   154→      CHECKPOINT_BRANCH,
   155→    ]);
   156→    if (parentExitCode !== 0) {
   157→      throw new Error("Failed to get parent commit");
   158→    }
   159→    const parent = parentStdout.trim();
   160→
   161→    // Create commit
   162→    const commitProc = Bun.spawn(
   163→      [
   164→        "git",
   165→        "commit-tree",
   166→        newTree,
   167→        "-p",
   168→        parent,
   169→        "-m",
   170→        `Add intent for ${folder}`,
   171→      ],
   172→      { stdout: "pipe", stderr: "pipe" }
   173→    );
   174→    const commitStdout = await new Response(commitProc.stdout).text();
   175→    const commitStderr = await new Response(commitProc.stderr).text();
   176→    if ((await commitProc.exited) !== 0) {
   177→      throw new Error(`Failed to create commit: ${commitStderr}`);
   178→    }
   179→    const newCommit = commitStdout.trim();
   180→
   181→    // Update branch reference
   182→    const { exitCode: updateRefExitCode } = await runGit([
   183→      "update-ref",
   184→      `refs/heads/${CHECKPOINT_BRANCH}`,
   185→      newCommit,
   186→    ]);
   187→    if (updateRefExitCode !== 0) {
   188→      throw new Error("Failed to update branch");
   189→    }
   190→
   191→    return relPath;
   192→  } finally {
   193→    // Clean up temp index
   194→    try {
   195→      await Bun.file(tmpIndex).delete();
   196→    } catch {
   197→      // Ignore cleanup errors
   198→    }
   199→  }
   200→}
