    10→function extractAssistantText(content: unknown): string | null {
    11→  if (!Array.isArray(content)) return null;
    12→
    13→  const texts: string[] = [];
    14→  for (const item of content) {
    15→    if (typeof item !== "object" || item === null) continue;
    16→    const obj = item as Record<string, unknown>;
    17→    if (obj.type !== "text") continue;
    18→    const text = obj.text;
    19→    if (typeof text === "string" && text.trim()) {
    20→      texts.push(text);
    21→    }
    22→  }
    23→
    24→  const joined = texts.join("\n").trim();
    25→  return joined || null;
    26→}
