    28→export function filterConversation(lines: string[]): ConvMsg[] {
    29→  const msgs: ConvMsg[] = [];
    30→
    31→  for (const raw of lines) {
    32→    const trimmed = raw.trim();
    33→    if (!trimmed) continue;
    34→
    35→    let obj: TranscriptMessage;
    36→    try {
    37→      obj = JSON.parse(trimmed);
    38→    } catch {
    39→      continue;
    40→    }
    41→
    42→    const typ = obj.type;
    43→    if (typeof typ !== "string") continue;
    44→
    45→    const message = obj.message;
    46→    if (typeof message !== "object" || message === null) continue;
    47→
    48→    const content = message.content;
    49→
    50→    if (typ === "user") {
    51→      if (typeof content === "string" && content.trim()) {
    52→        msgs.push({ role: "user", text: content.trim() });
    53→      }
    54→      continue;
    55→    }
    56→
    57→    if (typ === "assistant") {
    58→      const text = extractAssistantText(content);
    59→      if (text) {
    60→        msgs.push({ role: "assistant", text });
    61→      }
    62→      continue;
    63→    }
    64→  }
    65→
    66→  return msgs;
    67→}
    68→
    69→export function serializeForClaude(msgs: ConvMsg[]): string {
    70→  const lines: string[] = ["Conversation transcript (role: text):\n"];
    71→  for (const msg of msgs) {
    72→    lines.push(`[${msg.role}]\n${msg.text.trim()}\n`);
    73→  }
    74→  return lines.join("\n").trim() + "\n";
    75→}
