   343→      return { success: false, failedFindings: [...diffFindings, ...generalFindings] };
   344→    }
   345→
   346→    logger?.info("Created review", { prNumber, commentCount: comments.length });
   347→    console.log(`Created review with ${comments.length} diff comment(s)`);
