     1→import type { Finding, ProcessResult, ReviewResult } from "../types.js";
     2→import { getTracer, withSpan, type Logger } from "./observability.js";
     3→
     4→export const REVIEW_COMMENT_HEADER = "# Vibereq Review";
     5→
     6→export const SEVERITY_EMOJI: Record<string, string> = {
     7→  critical: ":x:",
     8→  major: ":warning:",
     9→  minor: ":grey_question:",
    10→  info: ":information_source:",
    11→};
    12→
    13→export const STATUS_EMOJI: Record<string, string> = {
    14→  fulfilled: ":white_check_mark:",
    15→  partial: ":yellow_circle:",
    16→  missing: ":red_circle:",
    17→  violation: ":x:",
    18→};
    19→
    20→interface ReviewComment {
    21→  path: string;
    22→  line: number;
    23→  start_line?: number;
    24→  body: string;
    25→}
    26→
    27→async function runCommand(cmd: string[]): Promise<ProcessResult> {
    28→  const proc = Bun.spawn(cmd, { stdout: "pipe", stderr: "pipe" });
    29→  const stdout = await new Response(proc.stdout).text();
    30→  const stderr = await new Response(proc.stderr).text();
    31→  const exitCode = await proc.exited;
    32→  return { stdout, stderr, exitCode };
    33→}
    34→
    35→export async function getCurrentPR(): Promise<number | null> {
    36→  const tracer = getTracer();
    37→
    38→  return withSpan(tracer, "getCurrentPR", async () => {
    39→    // GitHub Actions sets GITHUB_EVENT_PATH with the event payload
    40→    if (process.env.GITHUB_EVENT_NAME === "pull_request") {
    41→      const eventPath = process.env.GITHUB_EVENT_PATH;
    42→      if (eventPath) {
    43→        try {
    44→          const file = Bun.file(eventPath);
    45→          const event = await file.json();
    46→          const prNumber = event?.pull_request?.number;
    47→          if (typeof prNumber === "number") {
    48→            return prNumber;
    49→          }
    50→        } catch {
    51→          // Fall through to gh CLI
    52→        }
    53→      }
    54→    }
    55→
    56→    // Try to get PR from gh CLI
    57→    const result = await runCommand([
    58→      "gh",
    59→      "pr",
    60→      "view",
    61→      "--json",
    62→      "number",
    63→      "-q",
    64→      ".number",
    65→    ]);
    66→    if (result.exitCode === 0 && /^\d+$/.test(result.stdout.trim())) {
    67→      return parseInt(result.stdout.trim(), 10);
    68→    }
    69→
    70→    return null;
    71→  });
    72→}
    73→
    74→export async function getDiffLines(
    75→  baseBranch = "main"
    76→): Promise<Map<string, Set<number>>> {
    77→  const tracer = getTracer();
    78→
    79→  return withSpan(tracer, "getDiffLines", async () => {
    80→    const result = await runCommand([
    81→      "git",
    82→      "diff",
    83→      `${baseBranch}...HEAD`,
    84→      "--unified=0",
    85→    ]);
    86→    if (result.exitCode !== 0) {
    87→      return new Map();
    88→    }
    89→
    90→    const diffLines = new Map<string, Set<number>>();
    91→    let currentFile: string | null = null;
    92→
    93→    for (const line of result.stdout.split("\n")) {
    94→      // Match file header: +++ b/path/to/file.ts
    95→      if (line.startsWith("+++ b/")) {
    96→        currentFile = line.slice(6);
    97→        diffLines.set(currentFile, new Set());
    98→      }
    99→      // Match hunk header: @@ -old,count +new,count @@
   100→      else if (line.startsWith("@@") && currentFile) {
   101→        const match = /\+(\d+)(?:,(\d+))?/.exec(line);
   102→        if (match) {
   103→          const start = parseInt(match[1], 10);
   104→          const count = match[2] ? parseInt(match[2], 10) : 1;
   105→          const fileLines = diffLines.get(currentFile)!;
   106→          for (let i = start; i < start + count; i++) {
   107→            fileLines.add(i);
   108→          }
   109→        }
   110→      }
   111→    }
   112→
   113→    return diffLines;
   114→  }, { baseBranch });
   115→}
   116→
   117→function formatFindingForDiffComment(finding: Finding): string {
   118→  const severityEmoji = SEVERITY_EMOJI[finding.severity] || "";
   119→  const statusEmoji = STATUS_EMOJI[finding.status] || "";
   120→
   121→  return [
   122→    `${severityEmoji} **${finding.requirement}**`,
   123→    `Status: ${statusEmoji} ${finding.status}`,
   124→    "",
   125→    finding.details,
   126→  ].join("\n");
   127→}
   128→
   129→async function getCommitSha(prNumber: number, logger?: Logger): Promise<string | null> {
   130→  const tracer = getTracer();
   131→  return withSpan(tracer, "getCommitSha", async () => {
   132→    const shaResult = await runCommand([
   133→      "gh",
   134→      "pr",
   135→      "view",
   136→      String(prNumber),
   137→      "--json",
   138→      "headRefOid",
   139→      "-q",
   140→      ".headRefOid",
